  // Clock and reset
  reg clk;
  reg reset_n;

  // DUT interface
  reg        cs;
  reg        we;
  reg  [7:0] address;
  reg  [31:0] write_data;
  wire [31:0] read_data;

  // Instantiate DUT
  aes dut (
    .clk(clk),
    .reset_n(reset_n),
    .cs(cs),
    .we(we),
    .address(address),
    .write_data(write_data),
    .read_data(read_data)
  );

  // Clock generation
  always #5 clk = ~clk;

  // Write task
  task write_word;
    input [7:0]  addr;
    input [31:0] data;
    begin
      cs         = 1;
      we         = 1;
      address    = addr;
      write_data = data;
      #20;
      cs         = 0;
      we         = 0;
      #10;
    end
  endtask

  // Read task
  task read_word;
    input  [7:0]  addr;
    output [31:0] data;
    begin
      cs         = 1;
      we         = 0;
      address    = addr;
      write_data = 32'h0;
      #20;
      data = read_data;
      cs   = 0;
      #10;
    end
  endtask

  // AES-128 encrypt task
  task aes128_encrypt;
    input  [127:0] key;
    input  [127:0] block;
    output [127:0] result;
    reg [31:0] r0, r1, r2, r3;
    begin
      // Write key (128-bit: KEY0..KEY3 = key words, KEY4..KEY7 = 0)
      write_word(8'h10, key[127:96]);
      write_word(8'h11, key[95:64]);
